class Solution {
public:
    int ladderLength(string begin, string end, vector<string>& wl) {
        unordered_set<string> words(wl.begin(), wl.end());
        if (!words.count(end)) return 0;
        queue<pair<string, int>> q;
        q.push({begin, 1});
        while (!q.empty()) {
            auto [w, d] = q.front(); q.pop();
            if (w == end) return d;
            for (int i = 0; i < (int)w.size(); i++) {
                char orig = w[i];
                for (char c = 'a'; c <= 'z'; c++) {
                    w[i] = c;
                    if (words.count(w)) {
                        words.erase(w);
                        q.push({w, d + 1});
                    }
                }
                w[i] = orig;
            }
        }
        return 0;
    }
};
